const WEIGHTS: Record<PositionCategory, number> = {
  tactical: 0.25, balanced: 0.25, critical: 0.25, tricky: 0.15, endgame: 0.10,
};

export function getWeightedRandomPosition(): CuratedPosition & { id: string } {
  const roll = Math.random();
  let cum = 0;
  let cat: PositionCategory = "balanced";
  for (const [c, w] of Object.entries(WEIGHTS) as [PositionCategory, number][]) {
    cum += w; if (roll < cum) { cat = c; break; }
  }
  const pool = CURATED_POSITIONS.filter((p) => p.category === cat);
  const src = pool.length > 0 ? pool : CURATED_POSITIONS;
  const i = Math.floor(Math.random() * src.length);
  return { ...src[i], id: `curated-${CURATED_POSITIONS.indexOf(src[i])}` };
}

